import{_ as e,o as a,c as r,a2 as d}from"./chunks/framework.CBOyQ9KN.js";const u=JSON.parse('{"title":"Cursor 免费版（Free Tier）能力与限制调研报告","description":"","frontmatter":{},"headers":[],"relativePath":"12-free-tier/free-tier-report.md","filePath":"12-free-tier/free-tier-report.md","lastUpdated":null}'),l={name:"12-free-tier/free-tier-report.md"};function o(i,t,n,s,c,h){return a(),r("div",null,[...t[0]||(t[0]=[d(`<h1 id="cursor-免费版-free-tier-能力与限制调研报告" tabindex="-1">Cursor 免费版（Free Tier）能力与限制调研报告 <a class="header-anchor" href="#cursor-免费版-free-tier-能力与限制调研报告" aria-label="Permalink to &quot;Cursor 免费版（Free Tier）能力与限制调研报告&quot;">​</a></h1><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><p>基于实际 token 对 <code>api2.cursor.sh</code> 的 API 调测，结合代码逆向分析。</p><hr><h2 id="_1-订阅状态" tabindex="-1">1. 订阅状态 <a class="header-anchor" href="#_1-订阅状态" aria-label="Permalink to &quot;1. 订阅状态&quot;">​</a></h2><table tabindex="0"><thead><tr><th>项目</th><th>值</th></tr></thead><tbody><tr><td>当前套餐</td><td><strong>Free</strong></td></tr><tr><td>价格</td><td>$0</td></tr><tr><td>会员类型</td><td><code>free</code></td></tr><tr><td>结算周期</td><td>约 30 天一轮</td></tr><tr><td>Pro 试用资格</td><td><code>trialEligible: false</code>（已过期）</td></tr><tr><td>有效支付方式</td><td><code>hasValidPaymentMethod: false</code></td></tr><tr><td>上一个订阅</td><td><code>canceled</code>（曾订阅 Pro 后取消）</td></tr><tr><td>可升级方案</td><td><strong>Pro+</strong> $60/mo（$70 额度）</td></tr></tbody></table><hr><h2 id="_2-用量配额" tabindex="-1">2. 用量配额 <a class="header-anchor" href="#_2-用量配额" aria-label="Permalink to &quot;2. 用量配额&quot;">​</a></h2><h3 id="_2-1-核心限制" tabindex="-1">2.1 核心限制 <a class="header-anchor" href="#_2-1-核心限制" aria-label="Permalink to &quot;2.1 核心限制&quot;">​</a></h3><table tabindex="0"><thead><tr><th>项目</th><th style="text-align:center;">数值</th></tr></thead><tbody><tr><td>每月免费请求数</td><td style="text-align:center;"><strong>200 次</strong></td></tr><tr><td>用量计费</td><td style="text-align:center;"><code>noUsageBasedAllowed: true</code>（用完即止，不可超额）</td></tr><tr><td>已使用百分比</td><td style="text-align:center;">0%</td></tr><tr><td>超出提示</td><td style="text-align:center;"><code>&quot;You&#39;ve hit your 200 Free requests this month&quot;</code></td></tr><tr><td>限流类型</td><td style="text-align:center;"><code>free-user-rate-limit-exceeded</code></td></tr></tbody></table><h3 id="_2-2-计费周期" tabindex="-1">2.2 计费周期 <a class="header-anchor" href="#_2-2-计费周期" aria-label="Permalink to &quot;2.2 计费周期&quot;">​</a></h3><p>当前计费周期：<code>1780897455748</code> → <code>1783489455748</code>（Unix ms）</p><ul><li>开始：2026-06-08</li><li>结束：2026-07-08</li></ul><hr><h2 id="_3-可用模型" tabindex="-1">3. 可用模型 <a class="header-anchor" href="#_3-可用模型" aria-label="Permalink to &quot;3. 可用模型&quot;">​</a></h2><h3 id="_3-1-模型锁定机制" tabindex="-1">3.1 模型锁定机制 <a class="header-anchor" href="#_3-1-模型锁定机制" aria-label="Permalink to &quot;3.1 模型锁定机制&quot;">​</a></h3><p>免费用户受 <code>free_user_locked_model_2026_05</code> 实验开关控制：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>变量名:   free_user_locked_model_2026_05</span></span>
<span class="line"><span>类型:     Statsig 实验开关</span></span>
<span class="line"><span>可选值:   control | composer_2_5_fast | composer_2_5</span></span>
<span class="line"><span>判断逻辑: membershipType === FREE 时触发锁定</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="_3-2-可用模型列表" tabindex="-1">3.2 可用模型列表 <a class="header-anchor" href="#_3-2-可用模型列表" aria-label="Permalink to &quot;3.2 可用模型列表&quot;">​</a></h3><p>根据 <code>autoBucketModels: [&quot;default&quot;]</code> 和代码分析：</p><table tabindex="0"><thead><tr><th>模型</th><th style="text-align:center;">免费版可用?</th><th>说明</th></tr></thead><tbody><tr><td><code>default</code> 自动模型</td><td style="text-align:center;">✅</td><td>免费版只能使用自动（default）模型桶</td></tr><tr><td>Claude Sonnet 4</td><td style="text-align:center;">❌</td><td>仅付费版</td></tr><tr><td>Claude Opus 4</td><td style="text-align:center;">❌</td><td>仅付费版</td></tr><tr><td>GPT-4o</td><td style="text-align:center;">❌</td><td>仅付费版</td></tr><tr><td>Claude 3.5 Haiku</td><td style="text-align:center;">❌</td><td>仅付费版</td></tr><tr><td>o3/o4-mini</td><td style="text-align:center;">❌</td><td>仅付费版</td></tr></tbody></table><p><strong>锁定效果</strong>：免费用户不能手动选择具体模型，只能使用系统分配的&quot;自动&quot;模型桶。模型选择器显示锁状态：</p><div class="language-typescript vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">typescript</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">isFreeUserModelPickerLocked</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h3 id="_3-3-自动模型桶内容" tabindex="-1">3.3 自动模型桶内容 <a class="header-anchor" href="#_3-3-自动模型桶内容" aria-label="Permalink to &quot;3.3 自动模型桶内容&quot;">​</a></h3><p>根据 <code>composer_2_5_fast</code> 和 <code>composer_2_5</code> 等 variant 推测，免费版的自动模型可能包括：</p><ul><li><strong>control</strong>（默认分支）: Claude 3.5 Sonnet 级别</li><li><strong>composer_2_5_fast</strong>: 更快的响应模型</li><li><strong>composer_2_5</strong>: 标准的 Composer 模型</li></ul><p>实际路由由后端决定，客户端无权选择。</p><hr><h2 id="_4-各套餐对比" tabindex="-1">4. 各套餐对比 <a class="header-anchor" href="#_4-各套餐对比" aria-label="Permalink to &quot;4. 各套餐对比&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th style="text-align:center;">Free</th><th style="text-align:center;">Pro ($20/mo)</th><th style="text-align:center;">Pro+ ($60/mo)</th></tr></thead><tbody><tr><td>每月请求数</td><td style="text-align:center;"><strong>200</strong></td><td style="text-align:center;">500（fast）+ 无限（premium）</td><td style="text-align:center;">1500（fast）+ 无限（premium）</td></tr><tr><td>高级模型</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td>Cloud Agent</td><td style="text-align:center;">❌</td><td style="text-align:center;">有限</td><td style="text-align:center;">更多</td></tr><tr><td>Agent 用量</td><td style="text-align:center;">受限</td><td style="text-align:center;">基础</td><td style="text-align:center;">3x</td></tr><tr><td>选择模型</td><td style="text-align:center;">❌（自动锁定）</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td>图片上传</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr><tr><td>自定义模型 API</td><td style="text-align:center;">❌</td><td style="text-align:center;">✅</td><td style="text-align:center;">✅</td></tr></tbody></table><hr><h2 id="_5-免费版实际能做什么" tabindex="-1">5. 免费版实际能做什么 <a class="header-anchor" href="#_5-免费版实际能做什么" aria-label="Permalink to &quot;5. 免费版实际能做什么&quot;">​</a></h2><h3 id="✅-可以做" tabindex="-1">✅ 可以做 <a class="header-anchor" href="#✅-可以做" aria-label="Permalink to &quot;✅ 可以做&quot;">​</a></h3><ul><li>基础的 AI 代码补全（Tab）</li><li>Composer 对话（使用自动分配的模型）</li><li>Chat（使用自动分配的模型）</li><li>Cmd+K 内联编辑</li><li>代码检索（cursor-retrieval）</li></ul><h3 id="❌-不能做" tabindex="-1">❌ 不能做 <a class="header-anchor" href="#❌-不能做" aria-label="Permalink to &quot;❌ 不能做&quot;">​</a></h3><ul><li>手动选择模型（Sonnet/Opus/GPT-4o 等）</li><li>使用 Cloud Agent（云端 Agent）</li><li>超过 200 次请求/月</li><li>自定义 API Key（OpenAI/Anthropic 直连）</li><li>上传图片分析</li><li>运营团队/企业功能</li></ul><hr><h2 id="_6-api-端点权限验证" tabindex="-1">6. API 端点权限验证 <a class="header-anchor" href="#_6-api-端点权限验证" aria-label="Permalink to &quot;6. API 端点权限验证&quot;">​</a></h2><table tabindex="0"><thead><tr><th>API 端点</th><th style="text-align:center;">免费版访问权限</th></tr></thead><tbody><tr><td><code>AuthService/GetEmail</code></td><td style="text-align:center;">✅ 正常返回</td></tr><tr><td><code>AuthService/GetUserMeta</code></td><td style="text-align:center;">✅ 正常返回</td></tr><tr><td><code>DashboardService/GetCurrentPeriodUsage</code></td><td style="text-align:center;">✅ 正常返回</td></tr><tr><td><code>DashboardService/GetPlanInfo</code></td><td style="text-align:center;">✅ 正常返回</td></tr><tr><td><code>DashboardService/GetHardLimit</code></td><td style="text-align:center;">✅ 返回 <code>noUsageBasedAllowed: true</code></td></tr><tr><td><code>auth/full_stripe_profile</code></td><td style="text-align:center;">✅ 正常返回</td></tr><tr><td><code>auth/has_valid_payment_method</code></td><td style="text-align:center;">✅ 返回 <code>false</code></td></tr><tr><td><code>cursorvm-manager.com/model/...</code></td><td style="text-align:center;">❌ 需要付费模型权限</td></tr><tr><td><code>AuthService/EmailValid</code></td><td style="text-align:center;">❌ 需登录验证（限 Protobuf RPC）</td></tr></tbody></table><hr><h2 id="_7-关键发现" tabindex="-1">7. 关键发现 <a class="header-anchor" href="#_7-关键发现" aria-label="Permalink to &quot;7. 关键发现&quot;">​</a></h2><ol><li><p><strong>免费版的核心限制不是&quot;模型差&quot;，而是&quot;不能选模型&quot;</strong>。你用什么都由系统分配，通常是中低档模型。</p></li><li><p><strong>200次/月的配额很紧</strong>。代码中有明确提示：</p><div class="language- vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&quot;You&#39;ve hit your 200 Free requests this month&quot;</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div></li><li><p><strong>没用完的请求怎么算</strong>：从响应看，<code>totalPercentUsed: 0</code>，且 <code>remainingBonus: false</code>，免费版没有结转机制。</p></li><li><p><strong>Pro 版起跳价 $20/mo，而非 $10/mo</strong>。之前的 Hobby 计划似乎已取消，现在最低付费档是 Pro。</p></li><li><p><strong>免费版账号在之前的测试中实际上没有成功调用到模型</strong>。<code>cursorvm-manager.com</code> 的模型端点在免费版下返回空响应——无法确认具体分配的模型是什么。</p></li></ol><hr><h2 id="_8-数据来源" tabindex="-1">8. 数据来源 <a class="header-anchor" href="#_8-数据来源" aria-label="Permalink to &quot;8. 数据来源&quot;">​</a></h2><ul><li>直接 API 调用 <code>api2.cursor.sh/auth/full_stripe_profile</code></li><li>直接 API 调用 <code>api2.cursor.sh/aiserver.v1.DashboardService/GetCurrentPeriodUsage</code></li><li>逆向 <code>workbench.desktop.main.js</code> 中提取的 <code>free_user_locked_model_2026_05</code> 实验开关</li><li>代码中提取的 <code>Pl.FREE_USER_RATE_LIMIT_EXCEEDED</code> 错误定义</li><li>代码中提取的套餐切换逻辑 <code>Ja.FREE → Ja.PRO → Ja.PRO_PLUS → Ja.ULTRA</code></li><li>实际 token JWT 解码</li></ul>`,45)])])}const g=e(l,[["render",o]]);export{u as __pageData,g as default};
